import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../../../core/services/auth.service';
import { I18nService } from '../../../../core/services/theme-i18n.service';
import { User } from '../../../../core/models/models';

@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
})
export class NavbarComponent implements OnInit {
  user: User | null = null;
  menuOpen = false;

  constructor(public auth: AuthService, public i18n: I18nService) {}

  ngOnInit(): void {
    this.auth.user$.subscribe(u => this.user = u);
  }

  logout(): void { this.auth.logout(); }
  toggleMenu(): void { this.menuOpen = !this.menuOpen; }
}
<nav class="navbar">
  <div class="navbar-brand">
    <span class="brand-icon">⛅</span>
    <span class="brand-text">WeatherApp</span>
  </div>

  <button class="hamburger" (click)="toggleMenu()" [class.open]="menuOpen" aria-label="menu">
    <span></span><span></span><span></span>
  </button>

  <div class="navbar-menu" [class.open]="menuOpen">
    <ng-container *ngIf="auth.isLoggedIn">
      <a routerLink="/dashboard" routerLinkActive="active" (click)="menuOpen=false">
        {{ 'nav.dashboard' | translate }}
      </a>
      <a routerLink="/dashboard/favorites" routerLinkActive="active" (click)="menuOpen=false">
        {{ 'nav.favorites' | translate }}
      </a>
      <a routerLink="/dashboard/history" routerLinkActive="active" (click)="menuOpen=false">
        {{ 'nav.history' | translate }}
      </a>
      <a *ngIf="auth.isAdmin" routerLink="/dashboard/admin" routerLinkActive="active" (click)="menuOpen=false">
        {{ 'nav.admin' | translate }}
      </a>
    </ng-container>

    <div class="navbar-actions">
      <app-theme-toggle></app-theme-toggle>
      <app-lang-toggle></app-lang-toggle>
      <button *ngIf="auth.isLoggedIn" class="btn-logout" (click)="logout()">
        {{ 'nav.logout' | translate }}
      </button>
    </div>
  </div>
</nav>
